var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"어떻습니까?","JPN":"どうですか？","ENG":"So?","TWN":"怎麼樣？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"진실을 알고서 이면의 것들을 마주하게 된 소감은?","JPN":"真実を知って、裏世界の存在に向き合った感想は？","ENG":"How does it feel to know the truth and see what is on the other side?","TWN":"得知真相之後，面對異界事物的感想是什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…네. 이제야 알겠어요.","JPN":"……はい。やっとわかりました。","ENG":"...Yes. I understand now.","TWN":"…是，我現在才明白。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 수많은 그림자들에게서 느낀 기시감은… 착각이 아니었군요.","JPN":"あの数えきれないシャドウたちから感じた既視感は……私の勘違いではなかった。","ENG":"The sense of deja vu I felt from those countless Shadows... I wasn't mistaken.","TWN":"從無數暗影身上感受到的既視感…原來不是錯覺。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이런 식으로… 옛 세계에 남겨진 전우들을 몇 번씩이고 제 손으로 죽이고 있었던 거네요.","JPN":"こうして私は……旧世界に残された戦友たちを、何度も手にかけてきたのですね。","ENG":"I've been killing the comrades left behind in the old world again and again, with my own hands...","TWN":"我曾經用這種方式…親手殺了好幾次留存在舊世界的那些戰友。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"왼쪽 팔이 없었던 그 그림자는… 부전대장 타티아나.","JPN":"左腕がなかったあのシャドウは……副戦隊長のタテイアナ。","ENG":"The Shadow that had no left arm... That was Deputy Commander Tatiana.","TWN":"那個沒有左手臂的暗影是…副隊長塔蒂亞娜。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"가시로 뒤덮인 목 없는 그림자는… 말더듬이 신병 나탈리아.","JPN":"いばらに覆われた首なしのシャドウは……新兵のナタリア。","ENG":"The headless Shadow covered in thorns... That was the stuttering recruit, Natalia.","TWN":"被荊棘覆蓋，沒有脖子的暗影是…口吃的新兵那塔利亞。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그리고 익숙한 대검을 휘두르던 외눈의 그림자는…","JPN":"そして、見慣れた大剣を振るっていた隻眼のシャドウは……","ENG":"And the one-eyed Shadow that wielded a familiar greatsword must have been...","TWN":"還有揮舞熟悉大劍的獨眼暗影…"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"시렌 전대를 창설했던 제 아버지… 펠릭스였겠죠.","JPN":"シレン戦隊の創設者、私の父親……フェリックスだったのでしょう。","ENG":"...my father and founder of the Sirin Division... Felix.","TWN":"應該是我創立賽蓮戰隊的父親…緋莉克絲吧。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이제 말해줘요, 삼하인.","JPN":"教えてください、サウィン。","ENG":"Now, tell me, Samhain.","TWN":"現在就告訴我吧，薩溫。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신이 나에게서 원했던 건… 고작 내 영혼 하나가 아닌 거죠?","JPN":"あなたが私に求めていたのは……私の魂だけではない、そうでしょう？","ENG":"What you wanted from me... it wasn't just my soul, was it?","TWN":"你想從我身上得到的東西…不只是我的靈魂吧？"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"제가 원하는 건 당신이 모든 기억을 간직한 채, 계속해서 미래로 나아가는 겁니다.","JPN":"私の望みは、あなたがすべての記憶を持ったまま、更なる未来へ進むことです。","ENG":"What I want is for you to keep moving forward with all your memories.","TWN":"我想要的是妳珍藏所有記憶，繼續朝未來前進。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"저는 당신의 영혼을 차표 삼아 그 운명에 오른 승객일 뿐이죠.","JPN":"私はあなたの魂をチケットの代わりにして、運命に乗り込んだ乗客にすぎない。","ENG":"I am merely a passenger who boarded on your fate using your soul as a ticket.","TWN":"我只是個把你的靈魂當作車票，登上那個命運的乘客。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 선로의 끝에서… 우린 무엇을 마주하게 될까요?","JPN":"その線路の果てで……私たちは何に向き合うのでしょう。","ENG":"And what will we face... at the end of the tracks?","TWN":"在那條軌道的盡頭…我們會面臨什麼呢？"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"대적자, 마왕, 늑대… 그 모든 것을 만들어낸 <color=#ffd34c>원죄</color>","JPN":"敵対者、魔王、オオカミ……そのすべてを生み出した<color=#ffd34c>原罪</color>。","ENG":"The Antagonist, the Demon Lord, the Wolf... and the <color=#ffd34c>original sin</color> that created it all.","TWN":"敵對者、魔王、狼…打造出這一切的<color=#ffd34c>原罪</color>"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"전 수많은 이들과 계약하며 오랜 여행을 거쳐온 끝에, 그 원죄의 이름을 알아냈답니다.","JPN":"沢山の人と契約し、長い間旅を続け……私はその原罪の名がわかりました。","ENG":"After having traveled a long journey and making contracts with countless people, I have discovered the name of the original sin.","TWN":"我在和無數人簽訂契約，經過漫長的旅行後，打探出了那個原罪的名字。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"그 이름은… 탐미엘.","JPN":"その名は……タミエル。","ENG":"That name is... Tammiel.","TWN":"那個名字是…坦米爾。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"It is.","TWN":"沒錯。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그녀 또한 여느 마왕들과 마찬가지로 사도를 부리죠.","JPN":"そして彼女もまた、魔王と同じく使徒を従わせている。","ENG":"And she, too, like many other Demon Lords, has Apostles.","TWN":"而且她也像其他魔王一樣會操縱使徒。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"정말… <color=#ffd34c>그자</color>가 탐미엘의 사도라면…","JPN":"本当に……<color=#ffd34c>あの者</color>がタミエルの使徒なら……","ENG":"If... <color=#ffd34c>she</color> is truly Tammiel's Apostle...","TWN":"如果…<color=#ffd34c>那個人</color>真的是坦米爾的使徒…"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그걸 증명하는 방법은 뭐죠?","JPN":"どうやってそれを証明すればいいのです？","ENG":"...how can you prove that?","TWN":"要怎麼證明這件事？"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그들과 함께하다 보면, 머잖아 알게 될 겁니다.","JPN":"彼らと共にすれば……いずれわかるでしょう。","ENG":"Once you are with them, you will soon find out for yourself.","TWN":"和他們在一起的話，不久後就會知道了。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"세계는 세피로트 나무를 지배하는 마왕 탐미엘에 의해 순환을 거듭하는 것.","JPN":"世界はセフィロトの木を支配する魔王、タミエルによって循環を繰り返す。","ENG":"This world continues its cycle through the Demon Lord Tammiel, the ruler of the Tree of Sephiroth.","TWN":"世界是靠支配生命樹的魔王坦米爾反覆循環。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그 마왕의 사도는 당신처럼 영혼을 팔지 않더라도, 옛 세계의 기억을 온존하는 특별한 존재니까요.","JPN":"魔王の使徒はあなたのように魂を売らずとも、旧世界の記憶を失わない特別な存在ですから。","ENG":"And that Demon Lord's Apostle is a special being who can preserve the memories of the old world, even without selling her soul like you did.","TWN":"那個魔王的使徒是就算不像妳一樣出賣靈魂，也能保存舊世界記憶的特別存在。"},"stage":{"bg":"MS_1302","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"……그렇다면.","JPN":"……それなら。","ENG":"...Then.","TWN":"……那麼，"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 많은 이들 중, 당신이 저를 선택한 이유는 뭐죠?","JPN":"沢山の人の中から、あなたが私を選んだ理由は何ですか？","ENG":"Out of so many candidates, why pick me?","TWN":"在這麼多人當中，你為什麼選擇了我？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"악마에게 영혼을 팔면서까지 이전 세계의 기억을 온존하고.","JPN":"悪魔に魂を売ってまで、旧世界の記憶を保ち……","ENG":"I kept my memories of the old world by selling my soul to a demon.","TWN":"我甚至還把靈魂賣給惡魔，保存先前世界的記憶。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 기억을 통해 제가 거머쥐어야 할 미래는 무엇일까요?","JPN":"その記憶を通して私にどんな未来を掴めというのですか？","ENG":"So what future am I supposed to seize with those memories?","TWN":"我應該透過這段記憶抓住的未來是什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"탐미엘이 규정한 세계의 법칙에서 그녀에게 다다를 수 있는 방법은 하나입니다.","JPN":"タミエルが規定した世界の法則にて、彼女にたどり着く方法はただ1つ。","ENG":"Within the laws of the world as defined by Tammiel, there's only one way to reach her.","TWN":"在坦米爾規定的世界法則中，只有一個能達到她的方法。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"멸망한 세계의 망집으로부터 비롯되어… 그녀가 준비한 무대에서 놀아나는 자들.","JPN":"滅亡した世界への妄執により……彼女が用意した舞台で踊らされる者たち。","ENG":"Born from the delusions of a ruined world, they are the playthings dancing upon the stage she prepared.","TWN":"出於滅亡世界的妄執…在她準備的舞台上被擺布之人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그래요. 마왕에게 승리하여 세피로트의 나무를 거슬러 올라가는 것이죠.","JPN":"そう、魔王たちに勝利し、セフィロトを遡るのです。","ENG":"Exactly, you defeat the Demon Lord and climb back up the Tree of Sephiroth.","TWN":"沒錯，就是戰勝魔王，沿著生命樹逆行而上。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"한때 전대의 우두머리로서, 또한 관리국의 기술자로서 세계의 진실에 다다른 당신만이.","JPN":"かつて戦隊の長として、そして管理局の技術者として世界の真実に辿り着いたあなたこそが。","ENG":"Only you, a former division commander and engineer of the Administration who grasped the world's truth,","TWN":"妳曾經身為戰隊首領，也是管理局的技師，只有妳達到了世界的真相。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"세계가 탐미엘에게 다다를 분기점 중 하나가 되어줄 겁니다.","JPN":"世界をタミエルに導く分岐点の1つとなってくれるでしょう。","ENG":"can become one of the turning points that lead this world to Tammiel.","TWN":"妳將成為世界到達坦米爾的其中一個分岔點。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"분기점이라면…….","JPN":"分岐点ということは……","ENG":"By turning point...","TWN":"分岔點……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신의 뜻을 따른 들, 세계를 뒤덮는 멸망의 그림자를 피할 수는 없다는 건가요?","JPN":"あなたの言葉に従ったとて、世界を覆う滅亡の影から逃れる術はないということですか？","ENG":"Are you saying that even if I follow your lead, the shadow of apocalypse swallowing the world can't be avoided?","TWN":"意思是聽從妳旨意之人，躲不過籠罩世界的滅亡陰影嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"미래에 일어날 모든 일을 확정 지을 수는 없습니다.","JPN":"無数に枝分かれする未来のすべてを確定づけるなど、到底無理なことです。","ENG":"Not every event in the future can be certain.","TWN":"未來會發生的一切都無法確定。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"하지만 필연적으로 일어날 일에 대해 단편적으로 말씀드리자면…….","JPN":"しかし、必然的に起こるであろうことについて、少しだけお話ししますと……","ENG":"But if I speak in brief about what will inevitably come...","TWN":"但如果要針對必然會發生的事進行片面談論……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"세계의 가능성이 뿌리를 타고 숨겨져 있던 마왕의 이면을 드러내니.","JPN":"世界の可能性が根をたどり、隠れていた魔王の裏面を露わにし。","ENG":"As the world's possibilities climb the roots and bare the hidden face of the Demon Lord...","TWN":"世界的可能性會紮根，而魔王隱藏的底細則會表露。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"마침내, 암군이 옥좌에서 일어나리라.","JPN":"やがて、暗君が玉座から起き上がるであろう。","ENG":"At last, will the Ignorant Monarch rise from the throne.","TWN":"最終，昏君會從寶座上崛起。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"수년 전, 북방합의체 영토권- 시베리아 중부.","JPN":"数年前、北方合意体領土圏 - シベリア中部。","ENG":"Years ago, Northern Union Territory, Central Siberia.","TWN":"數年前，北方和議會領土圈－西伯利亞中部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_RAIN_02"},{"id":"L6_1","type":"subtitle","speaker":null,"text":{"KOREA":"북방합의체 프로젝트 총괄 연구시설, 섹터 C-4","JPN":"北方合意体プロジェクト総括研究施設、セクターC-4","ENG":"Northern Union Project, Central Lab Facility, Sector C-4","TWN":"北方和議會計畫統籌研究設施，C-4區域"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACKSON_NPC_NULL_QM","text":{"KOREA":"……결론. 청동나무의 성질을 역이용하여, 침식구역 중심부로부터 에너지 파형의 억제를 확인.","JPN":"……結論。青銅の木の性質を逆利用し、侵食区域の中心部からエネルギー波形の抑制を確認。","ENG":"...In conclusion, by exploiting the properties of the Bronze Tree, we confirmed suppression of the energy signature from the center of the Corrupted Area.","TWN":"……結論，反向利用青銅樹的性質，從侵蝕區域中心確認能量波形的抑制。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L9_1","type":"dialog","speaker":"JACKSON_NPC_NULL_QM","text":{"KOREA":"놀랍군요. 이론상으로만 가능하던 기술을 실현시키다니.","JPN":"これは驚きました。理論でしかなかった技術を実現させるとは。","ENG":"Impressive. You've realized a technology that lived only on paper until now.","TWN":"真令人驚訝，居然實現了只有理論上可行的技術。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JACKSON_NPC_NULL_QM","text":{"KOREA":"현시점에서 북방합의체의 기술력은 구 관리국에 비견된다 해도 과언이 아닐 겁니다.","JPN":"現時点で、北方合意体の技術力は旧管理局に匹敵すると言っても過言ではないでしょう。","ENG":"At this point, it's no exaggeration that the Northern Union's technology rivals the Old Administration's.","TWN":"北方和議會目前的技術能力說是與舊管理局不相上下也不為過。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"특정 분야에서의 기술력일 뿐이야. 구 관리국처럼 다방면에서 활용하는 건 불가능하겠지.","JPN":"特定の分野に限っての話だ。旧管理局のように、多方面での活用はまだ無理だろう。","ENG":"Only in certain lanes of research. We're nowhere near fielding it across the board the way the Old Administration did.","TWN":"只不過是在特定領域的技術能力而已，應該不可能像舊管理局一樣在多方面運用。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"무엇보다, 당장은 세계침식률 문제로 사용할 수 있는 부분이 제한돼서 큰 의미도 없고.","JPN":"なにより、今は世界侵食率の問題で使用できる部分が制限されているから大して意味はない。","ENG":"More to the point, its usable applications are limited with the Global Corruption rate where it is, so it's nothing to crow about.","TWN":"最重要的是，由於世界侵蝕率的問題，能立即使用的部分有限，也沒有太大的意義。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"챔버의 시니어라면 잘 알고 있지 않아?","JPN":"チェンバーのシニアならよく分かっていると思うのだが。","ENG":"You're Chamber's Senior. You know that as well as I do.","TWN":"密室的Senior應該很清楚吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"긍정. 하지만 해당 프로젝트에 관한 챔버 관리국의 지원은 고려할 필요가 있습니다.","JPN":"肯定。しかしこのプロジェクトに対するチェンバー管理局の支援については、再考する必要があります。","ENG":"Affirmation. Even so, Chamber's Administration should consider supporting this project.","TWN":"肯定，但需要考慮密室管理局對於該計畫的支援。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이유를 물어도 될까?","JPN":"理由を聞いても？","ENG":"May I ask why?","TWN":"我可以問理由嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"율리아 로즈노바. 제가 당신에게 협력하는 이유는 우리가 공통된 목적을 가지고 있기 때문입니다.","JPN":"ユリア・ローズノヴァ。わたくしがあなたに協力する理由は、共通の目的があるからです。","ENG":"Yulia Rosnova, my cooperation with you is based on our shared objective.","TWN":"茱莉亞·羅薩諾娃。我之所以跟你合作是因為我們有共同目的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"하지만 관리국이 묵인중인 시라사키 리프트 코퍼레이션의 대균열 지하공동에 관한 투자…….","JPN":"管理局が黙認しているシラサキ・リフト・コーポレーションの大亀裂地下空洞への投資……","ENG":"But the Administration's tacit approval of Sirasaki Lifting Company's investment into the underground caverns beneath the Grand Dimension Crevice...","TWN":"但管理局默認的白崎升降機公司的大峽谷地下共同相關投資……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그리고 관리국 소속 연구원인 에드윈 프리하트.","JPN":"そして管理局所属研究員のエッドウィン・プラハト。","ENG":"And the matter of Edwin Freehart, an Administration researcher.","TWN":"和管理局所屬研究員艾德溫·普立哈特，"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_NORMAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그를 책임자로 한 <color=#ffd34c>프로젝트 셰퍼드</color>의 물밑 작업까지.","JPN":"彼を責任者とした<color=#ffd34c>プロジェクト・シェパード</color>の準備を密かに行っていたこと。","ENG":"Along with the back-channel work on <color=#ffd34c>Project Shepherd</color> with him as lead.","TWN":"還有由他負責的<color=#ffd34c>牧羊人計畫</color>準備工作。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_NORMAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"당신이 바라는 답을 내기 전, 북방합의체의 최근 행보에 관한 해명이 필요할 것 같군요.","JPN":"あなたの望む答えを出す前に、最近の北方合意体の行動について説明していただきたい。","ENG":"Before I give you the answer you want, I'll need an explanation of the Northern Union's recent moves.","TWN":"在給出你想要的答案前，似乎需要對北方和議會最近的行動做出解釋。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"우연치 않게 관리국의 일에 손을 댄 건 미안하게 생각해.","JPN":"意図したわけではなかったが、管理局側に手を出してしまったことについては、悪いと思っている。","ENG":"I'll admit it's unfortunate we happened to put our hands into Administration business.","TWN":"無意間插手管理局的事，我感到抱歉。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"하지만 해명할 필요가 있을까?","JPN":"だが、説明する必要があるのか？","ENG":"But do I really need to explain myself?","TWN":"但是有必要解釋嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"내가 사욕으로 움직이지 않는다는 건 이미 숱하게 증명한 것 같은데.","JPN":"私が私欲のために動く人間ではないことは、すでに証明済みだと思うが。","ENG":"I think I've proven often enough that I don't act out of selfish motives.","TWN":"我應該已經證明了無數次自己不是出於私欲而行動。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"에드윈은 자신의 가족을 누구보다 중요시하는 남자입니다.","JPN":"エッドウィンは自分の家族を誰よりも大事にする男です。","ENG":"Edwin is a man who puts family above all else.","TWN":"艾德溫是個比任何人更加重視自己家人的男人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그의 딸이 프로젝트의 실험체로 사용되는 이상, 어떤 잡음이 생겨나도 이상하지 않죠.","JPN":"彼の娘をプロジェクトの実験体として利用した以上、何らかの衝突が起きたとしてもまったくおかしくない。","ENG":"With his daughter being used as a test subject, it's only natural for complications to arise.","TWN":"既然他女兒被用來當作計畫的實驗體，出現任何爭議都不奇怪。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"변수가 될 수 있는 요소를 방임하는 것. 그것조차 당신… 아니, 삼하인의 계획입니까?","JPN":"そんな要素を放っておくこと。それもあなた……いや、サウィンの計画ですか？","ENG":"Leaving a potential variable unattended, was that your plan as well, or Samhain's?","TWN":"放任可能成為變數的因素，就連這件事也是你…不，是薩溫的計畫嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"목적은 처음과 동일해.","JPN":"目的は最初と変わらない。","ENG":"The objective hasn't changed since the start.","TWN":"我的目的跟一開始一樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그렇기에 협력관계가 온전한 이상, 우린 당신이 원하는 모든 걸 지원할 테고.","JPN":"だからこそ、協力関係が保たれる限り、私たちは君が望むすべてを支援する。","ENG":"As long as our cooperation holds, we'll give you everything you've asked for.","TWN":"既然合作關係如此完好， 我們也會支援你想要的一切。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이제, 당신의 대답을 들을 수 있을까?","JPN":"では、君の答えを聞かせてもらえるかな？","ENG":"Now, may I hear your answer?","TWN":"現在能聽到你的回答嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨도 참. 왜 저런 여자의 말을 곧이곧대로 들어주는 거람?","JPN":"ジャクソンさんったら、なんであの女の言う通りにしてやってるの？","ENG":"Honestly. Why does Mr. Jackson take a woman like that at face value?","TWN":"傑森也真是的，為什麼要聽信那種女人的話？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"곳곳에서 나는 화학 약품 냄새도 최악인데, 잭슨 씨가 있으니까 소란 피울 수도 없잖아.","JPN":"あっちこっちからする化学薬品の匂いも最悪だし、ジャクソンさんがいるから派手なこともできないし。","ENG":"Place reeks of chemicals, too. I can't even make a fuss with Mr. Jackson here.","TWN":"到處都是化學藥品的味道已經糟糕透頂，有傑森在也不能引起騷亂。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"저, 저기…….","JPN":"あ、あの……","ENG":"E-excuse me...","TWN":"那、那個……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"북방합의체 건물에 있는 것도 화나는데, 얌전히 있으라니 완전 고문 아니야?","JPN":"北方合意体の建物にいるだけでも気分悪いのに、大人しく待ってろだなんて拷問じゃない。","ENG":"Being stuck in a Northern Union building already ticks me off, and now I'm told to sit pretty, that's torture.","TWN":"在北方和議會的建築裡已經很生氣，還要我乖乖待著，這簡直就是拷問吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아, 그렇게 생각하니 조금 버틸만한 것 같기도…….","JPN":"あ、そう思ったらちょっと耐えられる気がしてきた……","ENG":"Though, thinking about it that way kind of makes it bearable...","TWN":"啊，這樣一想，好像還能稍微撐住……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"제 말, 들리시나요…?","JPN":"あの、聞こえてますか……？","ENG":"C-can you hear me...?","TWN":"聽得到我說話嗎…？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네-! 왜 그러시죠?","JPN":"はい！　どうしました？","ENG":"Yes! What is it?","TWN":"嗯–！怎麼了？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"히, 히익…!!","JPN":"ひ、ひいっ……！！","ENG":"E-eeek...!","TWN":"咿、咿咿…！！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Ah.","TWN":"啊，"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저질렀다. 예민해서 나도 모르게 소리부터 질렀네.","JPN":"しまった。気が立っててつい大声になっちゃった。","ENG":"Whoops. I snapped without thinking.","TWN":"搞砸了，因為太敏感，所以不自覺地叫了一聲。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"북방합의체 놈들은 전부 죽을 만큼 싫지만, 저런 어린애한테 화풀이하면 안 되겠지.","JPN":"北方合意体のやつらなんて死ぬほど嫌いだけど、あんな子どもに八つ当たりしちゃダメだよね。","ENG":"I hate every last Northern Union dog to death, but taking it out on a kid isn't it.","TWN":"雖然我對北方和議會所有的人恨之入骨，但總不能把氣出在那種小孩身上。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"미안해요. 제가 지금 많이… 아니, 조금 예민한 상태라서요.","JPN":"ごめんなさい。私今すごく……いや、ちょっとだけ、気が立ってて。","ENG":"Sorry. I'm very... no, a little on edge right now.","TWN":"抱歉，因為我現在處於非常…不，有點敏感的狀態。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"제, 제가 귀찮게 군 탓이 아닌가요…?","JPN":"わ、私が声かけたせいじゃないんですか……？","ENG":"D-did I make a nuisance of myself...?","TWN":"是、是不是因為我纏著妳的關係…？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그럼요. 저한테 무슨 볼일이라도 있으신가요?","JPN":"そんなことないですよ。それで、私に何か用ですか？","ENG":"Not at all. Did you need something from me?","TWN":"當然，妳找我有什麼事嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"아, 실은… 율리아 님이 손님을 맞이하는 건 드문 일이라, 어떤 분인지 궁금했어요.","JPN":"あ、実は……ユリア様にお客様が来るのは珍しいことなので、どんな方なのかと思って。","ENG":"O-oh, it's just, Ms. Yulia doesn't usually receive guests, so I was curious.","TWN":"啊，其實…是因為茱莉亞很少會接見客人，我很好奇是什麼樣的人。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"언니가 소, 소, 손님분이세요?","JPN":"あなたが、お、お、お客様ですか？","ENG":"A-are you... a g-guest, ma'am?","TWN":"姐姐，妳、妳是客人嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"아. 또 말 더듬었다.","JPN":"あ、また噛んじゃった。","ENG":"Ah. I-I stammered again.","TWN":"啊，說話又結巴了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"손님… 뭐, 비슷하긴 하죠. 잭슨 씨만 아니었다면 이런 곳에 올 일도 없었겠지만.","JPN":"お客様……まあ、そうですね。ジャクソンさんとじゃなければ、こんなとこに来ることもなかったけど。","ENG":"A guest... I guess you could say that. If it weren't for Mr. Jackson, I'd never set foot in a place like this.","TWN":"客人…嗯，差不多吧。雖然要不是傑森，我也不會來到這種地方。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"NATALIA_UNION_NULL_QM","text":{"KOREA":"다, 다행이다. 폭실이는 길 잃은 줄 알고 엄청 걱정했어요.","JPN":"よ、よかった。モコが道に迷ったのかとすごく心配していて。","ENG":"Th-thank goodness. Fluffox thought you got lost and was really worried.","TWN":"那、那就好，我還以為福實迷路了，覺得很擔心。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와, 그쪽 이름이 폭실이에요? 귀엽다.","JPN":"へえ、モコって言うんですか？　かわいい名前。","ENG":"Wow, its name is Fluffox? That's cute.","TWN":"哇，妳的名字叫福實嗎？真可愛。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"저, 저는 나탈리아예요. 이쪽이… 제 친구 폭실이고요.","JPN":"わ、私はナタリアです。こっちが……私の友だち、モコです。","ENG":"I-I'm Natalia. And this is my friend, Fluffox.","TWN":"我、我叫那塔利亞，這是…我的朋友福實。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L29_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실이가 친해지려면 좋아하는 걸 통해 마음을 나눠보래요.","JPN":"モ、モコが、仲良くするためには好きなものを渡して心を分かち合ってみろ、って。","ENG":"F-Fluffox says the best way to make friends is to share things we like.","TWN":"福、福實說如果想變得親近，就要透過喜歡的東西來分享心意。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"사탕 드실래요?","JPN":"キャンディー食べますか？","ENG":"Would you like a candy?","TWN":"妳要吃糖果嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어… 사탕은 조금…….","JPN":"え……キャンディーはちょっと……","ENG":"Uh... Candy's a bit...","TWN":"哦…糖果有點……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"엣.","JPN":"えっ。","ENG":"Eh.","TWN":"欸。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이거, 무슨 맛이죠?","JPN":"これ、何味ですか？","ENG":"What flavor is this?","TWN":"這是什麼口味？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"새, 생강 맛이요. 율리아 님이 몸에 좋은 약은 입에 쓰다고 해서 자주 먹어요.\xA0\xA0","JPN":"ジ、ジンジャー味です。健康にいいものほど苦いって、ユリア様に言われたからよく食べてます。\xA0\xA0","ENG":"G-ginger. Ms. Yulia says good medicine tastes bitter, so we have it a lot.\xA0\xA0","TWN":"是、是生薑口味，茱莉亞說良藥苦口，所以常常吃。\xA0\xA0"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"컥! 커억! 커허어억!!","JPN":"げっ！　げほっ！　くはああっ！！","ENG":"Gah! Kahh! Blegh!!","TWN":"咳！咳呃！咳呃呃呃！！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"아, 뱉었다.","JPN":"あ、吐いた。","ENG":"Oh, you spat it out.","TWN":"啊，吐掉了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"유감이네. 평범한 사탕 같아도 제법 비싼 재료로 만들어진 건데.","JPN":"心外だな。ただのキャンディーのように見えて、原料には高価なものを使っているんだが。","ENG":"What a shame. Although it looks like ordinary candy, it's made with some expensive ingredients.","TWN":"真遺憾，雖然看起來像普通的糖果，卻是用相當昂貴的材料製成的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"흡혈귀 입맛에는 별로인가 봐?","JPN":"吸血鬼の口には合わなかったようだな？","ENG":"Not to a vampire's taste, I take it?","TWN":"看來不合吸血鬼的口味啊？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"흥. 뻔뻔한 것도 정도가 있지. 내가 누구 때문에 이렇게 됐는데?","JPN":"ふん。図々しいにもほどがあるね。誰のせいでこうなったと思ってるの？","ENG":"Hmph. There's shameless, and then there's you. Who do you think made me like this?","TWN":"哼，厚臉皮也要有限度，我是因為誰才變成這樣的？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨가 있는 걸 다행으로 여겨. 아니었으면 그쪽 목부터 따버렸을 테니까.","JPN":"今ここにジャクソンさんがいることに感謝するんだね。そうじゃなかったら、速攻であなたの首跳ね飛ばしてたから。","ENG":"Be grateful Mr. Jackson's here. If he weren't, I would've slit your throat already.","TWN":"妳要慶幸有傑森在，不然我應該會先砍下妳的脖子。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그 가냘픈 몸으로 가능하려나?","JPN":"その華奢な体でできるかな？","ENG":"With that frail little body? I'd like to see you try.","TWN":"憑妳那柔弱的身體辦得到嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"왜, 가냘픈 몸으로 뭘 할 수 있는지 한번 보여줘?","JPN":"この華奢な体で何ができるか、見せてあげようか？","ENG":"Oh? Want me to show you what this \\"frail little body\\" can do?","TWN":"怎麼？要讓妳見識一下能用柔弱的身體做些什麼事嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어라.","JPN":"あれ。","ENG":"Huh?","TWN":"咦。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"무, 무기가… 왜 이렇게 무겁지?","JPN":"ぶ、武器が……なんでこんなに重い？","ENG":"W-why does... my weapon feel so heavy?","TWN":"武、武器…為什麼這麼重？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"방금 먹은 사탕. 꽤 강한 CRF 억제제야. 나탈리아는 능력을 다루는데 서툴러서 약처럼 복용하거든.","JPN":"さっき食べたキャンデイーはかなり強いCRF抑制剤だ。ナタリアは能力の扱いが未熟で、薬のように食べさせている。","ENG":"The candy you just ate, it's a strong CRF suppressant. Natalia takes it like medicine because she's clumsy with her ability.","TWN":"妳剛才吃的糖果，是強效CRF抑制劑。那塔利亞不太會操控能力，所以把它當藥一樣服用。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"잠깐 먹은 것만으로도 S급 카운터에게 효력이 있다니, 공들여 만든 보람이 있네.","JPN":"少し口に入れただけでもS級カウンターに効果を発揮するとは……苦労して作った甲斐があったな。","ENG":"If a single dose works on a Grade S Counter, I'd say the effort paid off.","TWN":"光是吃一下就對S級制裁者有效果，不枉費我花費心血製作。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이 음침녀…! 처음부터 다 알면서 나를 농락해?","JPN":"この陰湿女……！　最初から知っててやらせたな？","ENG":"You creepy witch...! You were playing me from the start, weren't you?!","TWN":"這陰險的女人…！妳從一開始就知道卻戲弄我？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L12_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"그만. 더 이상의 논쟁은 불필요합니다, 예니카.","JPN":"そこまで。それ以上の争いは不要です、イェニカ。","ENG":"Enough. Further quarrel is unnecessary, Yanikka.","TWN":"夠了，不需要再爭論下去，耶妮卡。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"재, 잭슨 씨?","JPN":"ジャ、ジャクソンさん？","ENG":"M-Mr. Jackson?","TWN":"傑、傑森？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이건… 그게, 그러니까…….","JPN":"これは……えっと、その……","ENG":"Th-this is... I mean...","TWN":"這是…那個，所以……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L17_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"이곳에서의 일은 끝마쳤습니다. 오늘은 이만 관리국으로 복귀하죠.","JPN":"ここでの用事は終わりました。そろそろ管理局に復帰しましょう。","ENG":"We're done here. Let's return to the Administration for today.","TWN":"這裡的事已經告一段落，今天就回管理局吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"계약대로, 챔버 대균열에서의 연구는 넘어가드리겠습니다.","JPN":"契約通り、チェンバー大亀裂での研究の件は見逃してあげます。","ENG":"As agreed, we'll hand over the research on Chamber's Grand Dimension Crevice.","TWN":"我會按照契約，跳過在密室大峽谷的研究。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"하지만 이건 관리국이 아닌 제 개인의 독단.","JPN":"しかしこれは管理局ではなく、わたくし個人の独断。","ENG":"But that is my personal decision, not the Administration's.","TWN":"但這不是管理局，而是我個人的獨斷。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"다른 이들에게 프로젝트가 발각된다면, 조속히 자산을 회수할 필요가 있을 겁니다.","JPN":"他の者にプロジェクトが発覚すれば、速やかに資産を回収することになるでしょう。","ENG":"If others catch wind of the project, we'll need to recover our assets quickly.","TWN":"要是被其他人發現計畫，就必須迅速收回資產。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"응. 이쪽도 <color=#ffd34c>약속</color>은 지킬게.","JPN":"ああ。こちらも<color=#ffd34c>約束</color>は守ろう。","ENG":"Understood. I'll keep our <color=#ffd34c>promise</color>.","TWN":"嗯，我們這邊也會遵守<color=#ffd34c>約定</color>。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"거래 성립이야. 시니어 잭슨.","JPN":"取引は成立した、シニア・ジャクソン。","ENG":"We have a deal, Senior Jackson.","TWN":"成交，Senior傑森。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"……역시, 저는 마음에 안 들어요.","JPN":"……やっぱり、気に入りません。","ENG":"...I still don't like this.","TWN":"……果然，我不喜歡她。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨도 보셨죠? 그 여자. 지가 무슨 왕이라도 된 줄 안다고요.","JPN":"ジャクソンさんも見たでしょう？　あの女、まるで王様気取りじゃないですか。","ENG":"You saw it too, Mr. Jackson. That woman struts around like she's queen of the world.","TWN":"傑森，你也有看到吧？那個女人以為自己成了什麼王。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"확실히 고삐를 죄일 상대는 아니지만, 북방합의체와 우호적 관계 유지는 필수적입니다.","JPN":"取り締まりが効くような相手ではありませんが、北方合意体とは友好的な関係を保たねばなりません。","ENG":"She's not someone to leash easily, true, but keeping friendly ties with the Northern Union is essential.","TWN":"雖然的確不是需要壓制的對手，但要與北方和議會保持友好關係必不可少。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"분명 먼 미래에 그들의 힘이 필수불가결한 순간이 오겠죠.","JPN":"遠い未来、きっと彼らの力が必要不可欠となる瞬間が訪れます。","ENG":"Far down the line, I'm certain a day will come when their strength will be indispensable.","TWN":"在遙遠的未來，應該會有他們的力量不可缺少的時刻到來。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"켁. 제 쪽에서 합의체의 힘을 빌려야 하는 순간이라니 곧 죽어도 싫네요.","JPN":"げっ。こっちから北方合意体に頭を下げる瞬間だなんて死んでもごめんですね。","ENG":"Ugh. A day where I have to borrow the Northern Union's strength? Over my dead body.","TWN":"咳，居然有我這裡需要借助和議會力量的時刻，我死都不願意。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"부정. 죽음이 만연하는 세상이 온다면, 선과 악의 구분은 어떤 가치도 없을 겁니다.","JPN":"否定。死が蔓延る世の中では、善悪の区別は価値を持たないでしょう。","ENG":"Negative. If a world of rampant death arrives, good and evil will lose all meaning.","TWN":"否定，如果死亡蔓延的世界到來，善惡的區分將會毫無價值。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"음… 역시 싫어요.","JPN":"うーん……やっぱり嫌です。","ENG":"Mm... I still hate it.","TWN":"嗯…我還是不願意。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그렇게 될 바에 멸망하라지, 세상.","JPN":"そうなるくらいなら世界なんて滅んでしまえばいい。","ENG":"If that's our future, then let the world burn.","TWN":"與其這樣，不如世界滅亡吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"예니카. 저는 이런 몸이 된 뒤로 추상적인 관념을 배제하고 현실을 바라보았습니다만.","JPN":"イェニカ、わたくしはこの体になって以来、抽象的な観念を排除して現実を見据えてきました。","ENG":"Yanikka. Since becoming what I am, I've tried to strip out abstractions and see only reality.","TWN":"耶妮卡，自從我變成這樣之後，就屏除抽象觀念，望向現實。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"끝끝내 버리지 못한 인간의 감정이 판단을 흐리게 만들곤 합니다.","JPN":"しかし、捨てきれなかった人間としての感情が判断力を鈍らせることがあります。","ENG":"And yet the human feelings I couldn't quite discard still cloud my judgment.","TWN":"但最終還是沒能拋下的人類情感，總會模糊判斷。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"중요한 순간, 저는 시니어로서의 역할을 저버릴지도 모르죠.","JPN":"肝心な場面で、わたくしはシニアとしての役割に背くかもしれません。","ENG":"At a crucial moment, I may fail to play my part as Senior.","TWN":"也許在重要時刻，我會背棄身為Senior的職責。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"이에 따른 결론은…….","JPN":"これによる結論は……","ENG":"Therefore, my conclusion is–","TWN":"因此得出的結論是……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"Huh?","TWN":"這是？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"과거, 관리국의 한 기술자가 만들어낸 물건입니다.","JPN":"過去、管理局のとある技術者が作り出したものです。","ENG":"It's something a certain Administration engineer made long ago.","TWN":"這是過去管理局的一個技師做出的物品。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"인류의 생존, 그리고 발전에 이바지한 그의 업적을 기리기 위해, 저는 제가 지닌 시니어 코드를 이곳에 담아 오랜 기간 간직해왔죠.","JPN":"人類の生存、そして発展に貢献した彼の功績を称えるために、わたくしは自分のシニアコードをここに保存し、長い間大事にしまっておきました。","ENG":"To honor his service to humanity's survival and progress, I sealed my Senior Code into it and kept it safe for years.","TWN":"為了紀念他對人類生存和發展貢獻的功績，我把自己擁有的Senior代碼放在這裡，保存了很長一段時間。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"이것을 이용하면 챔버 관리국 테라브레인의 가상 단말에 접근할 수 있을 겁니다.","JPN":"これを使えば、チェンバー管理局テラブレインの仮想端末にアクセスできるでしょう。","ENG":"With this, you can access the Chamber Administration's Terrabrain virtual terminal.","TWN":"用這個應該可以進入密室管理局特拉大腦的虛擬終端。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"가, 갑자기 무슨 말씀이세요, 잭슨 씨?","JPN":"きゅ、急に何を言ってるんですか、ジャクソンさん？","ENG":"W-where is this coming from, Mr. Jackson?","TWN":"傑森，你、你突然在說什麼？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런 말은… 플래그랄까. 죽는 사람이 내뱉는 대사라고요?","JPN":"そういう言葉は……フラグというか、死ぬ予定の人が言うセリフですよ？","ENG":"That's... that's a death flag, you know? Things people say right before they die?","TWN":"那種話…應該說是立死旗嗎？是要死的人說的台詞嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"만약을 대비해 가능성을 열어두는 것뿐입니다.","JPN":"万が一のために、可能性を開いておくだけです。","ENG":"I'm merely leaving our options open, just in case.","TWN":"我只是以防萬一，先提出可能性而已。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"S급 카운터인 당신이라면, 챔버에 일어날 이상현상에 발빠르게 대처할 수 있겠죠.","JPN":"S級カウンターであるあなたなら、チェンバーに起こる異常現象に迅速に対応できます。","ENG":"As a Grade S Counter, you can respond swiftly to any anomalies that hit Chamber.","TWN":"如果是妳這個S級制裁者，應該能迅速應對密室裡發生的異常現象。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"전 괜찮으니 시니어 코드는 넣어두세요, 잭슨 씨.","JPN":"私のことは気にしないで、シニアコードは取っておいてください、ジャクソンさん。","ENG":"I'll be fine, so keep your Senior Code, Mr. Jackson.","TWN":"我沒關係，你就先收起Senior代碼吧，傑森。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저도 염치가 있지. 어떻게 은인을 등쳐먹을 생각을 하겠어요?","JPN":"私、恩人を利用するほど厚顔無恥じゃありませんよ。","ENG":"I have some shame, you know. I'm not about to scam the man who saved me.","TWN":"我也懂得廉恥，怎麼會想著要敲詐恩人呢？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"응답. 거듭 말하지만 가능성을 열어두는 것뿐입니다.","JPN":"応答。もう一度言いますが、可能性を開いておくだけです。","ENG":"Response. As I said, it's only to keep our options open.","TWN":"回答，我再說一次，只是先提出可能性而已。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만 잭슨 씨가 있다면 그런 가능성은 현격히 줄어드는 셈이잖아요?","JPN":"でもジャクソンさんがいれば、その可能性は極めて低いんですよね？","ENG":"But if you're around, those options won't be necessary, right?","TWN":"但要是有你在，那種可能性就會顯著減少吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그러니까 이상한 생각 금지!","JPN":"だから変なこと考えるのは禁止です！","ENG":"So nix the weird thoughts!","TWN":"所以不准有奇怪的念頭！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"S급 카운터인 제가 있으니, 잭슨 씨가 위험할 일은 없을 거예요.","JPN":"S級カウンターの私がいるから、ジャクソンさんの身に危険が及ぶことはありません。","ENG":"I'm a Grade S Counter, so nothing's going to happen to you on my watch.","TWN":"有我這個S級制裁者在，你不會有任何危險。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"알겠습니다, 예니카.","JPN":"わかりました、イェニカ。","ENG":"Understood, Yanikka.","TWN":"知道了，耶妮卡。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"이후의 일은, 당신이 어떤 <color=#ffd34c>선택</color>을 내리든 존중하죠.","JPN":"今後のことについてあなたがどんな<color=#ffd34c>選択</color>をしても、わたくしはそれを尊重します。","ENG":"Whatever <color=#ffd34c>choice</color> you make after this, I'll respect it.","TWN":"之後的事，不管妳做出什麼<color=#ffd34c>選擇</color>，我都會尊重。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};